using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddSingleton<Notepad>();

builder.Services.AddChatClient(chatBuilder => chatBuilder
    .UseOpenAIChatClient(
        builder.Configuration["AI:Model"] ?? "gpt-4o-mini-2024-07-18",
        builder.Configuration["AI:ApiKey"]
            ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
            ?? throw new InvalidOperationException(
                "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.")));

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var notepad = host.Services.GetRequiredService<Notepad>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(notepad.TakeNote),
    AIFunctionFactory.Create(notepad.ReadNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research a topic the user
        provides by searching the web and taking notes on key findings.

        Follow this workflow:
        1. Break the topic into 2-3 specific search queries.
        2. For each query, call SearchWebAsync to get results.
        3. After each search, call TakeNote to record the most important findings
           with a descriptive title.
        4. After all searches, call ReadNotes to review your collected findings.
        5. Produce a final summary that synthesizes your notes into a cohesive overview
           with key takeaways and sources.

        Always cite sources from the search results. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings.",
    tools: tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("║  Enter a topic to research, or quit  ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic: ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic)
        || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    notepad.Clear();

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine(new string('─', 50));

    await foreach (var update in agent.RunStreamingAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        options: new ChatClientAgentRunOptions
        {
            ChatOptions = new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 2048,
            },
        }))
    {
        if (!string.IsNullOrEmpty(update.Text))
        {
            Console.Write(update.Text);
        }
    }

    Console.WriteLine();
    Console.WriteLine(new string('─', 50));
    Console.WriteLine();
}

