using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability for the research agent.
/// Uses the Google Custom Search JSON API when configured,
/// otherwise returns simulated results for demonstration.
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new();

    [Description("Searches the web for a given query and returns a list of results with titles, snippets, and URLs.")]
    public static async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up on the web.")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        var apiKey = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_API_KEY");
        var cx = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_CX");

        if (!string.IsNullOrEmpty(apiKey) && !string.IsNullOrEmpty(cx))
        {
            return await SearchGoogleAsync(query, apiKey, cx, cancellationToken);
        }

        return GetSimulatedResults(query);
    }

    private static async Task<IReadOnlyList<SearchResult>> SearchGoogleAsync(
        string query, string apiKey, string cx, CancellationToken cancellationToken)
    {
        var url = $"https://www.googleapis.com/customsearch/v1?key={apiKey}&cx={cx}&q={Uri.EscapeDataString(query)}&num=5";

        var response = await s_httpClient.GetStringAsync(url, cancellationToken);
        using var doc = JsonDocument.Parse(response);

        var results = new List<SearchResult>();

        if (doc.RootElement.TryGetProperty("items", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(5))
            {
                results.Add(new SearchResult
                {
                    Title = item.GetProperty("title").GetString() ?? "",
                    Snippet = item.GetProperty("snippet").GetString() ?? "",
                    Url = item.GetProperty("link").GetString() ?? "",
                });
            }
        }

        return results;
    }

    private static IReadOnlyList<SearchResult> GetSimulatedResults(string query)
    {
        var hash = Math.Abs(query.GetHashCode());
        var domains = new[] { "wikipedia.org", "nature.com", "arxiv.org", "bbc.com", "reuters.com" };
        var results = new List<SearchResult>();

        for (var i = 0; i < 3; i++)
        {
            var domain = domains[(hash + i) % domains.Length];
            results.Add(new SearchResult
            {
                Title = $"{query} - Result {i + 1} from {domain}",
                Snippet = $"This is a simulated search result for \"{query}\". "
                    + $"In a production scenario, this would contain real content from {domain}. "
                    + "Set GOOGLE_SEARCH_API_KEY and GOOGLE_SEARCH_CX environment variables to use live search.",
                Url = $"https://{domain}/wiki/{Uri.EscapeDataString(query.Replace(' ', '_'))}",
            });
        }

        return results;
    }
}

public sealed class SearchResult
{
    public required string Title { get; init; }
    public required string Snippet { get; init; }
    public required string Url { get; init; }

    public override string ToString() => $"[{Title}]({Url}): {Snippet}";
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// A note-taking tool that the agent uses to store and organize research findings.
/// </summary>
public sealed class Notepad
{
    private readonly List<Note> _notes = [];

    [Description("Takes a note to record a research finding. Use this to save important information discovered during web searches.")]
    public string TakeNote(
        [Description("A short descriptive title for the note.")] string title,
        [Description("The content of the note, including key facts and source URLs.")] string content)
    {
        _notes.Add(new Note(title, content));

        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Reads all notes taken so far during this research session. Use this to review findings before writing a summary.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");

        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();

    private sealed record Note(string Title, string Content);
}

using System.ComponentModel;
